class OptimaNotificationLightweight{constructor(){this.baseUrl=window.location.origin+'/optima/public';this.pollingInterval=30000;this.pollingTimer=null;this.isPolling=false;this.lastNotificationId=0;this.badge=null;this.dropdownMenu=null;this.notificationSound=null;this.enableSound=true;this.notificationQueue=[];this.isShowingNotification=false;this.shownPopupIds=new Set();this.loadShownPopups();console.log('🚀 Optima Notification Lightweight Client initialized');this.init()}loadShownPopups(){try{const stored=localStorage.getItem('optima_shown_popup_ids');if(stored){const ids=JSON.parse(stored);this.shownPopupIds=new Set(ids);const sevenDaysAgo=Date.now()-(7*24*60*60*1000);const cleanedIds=Array.from(this.shownPopupIds).filter(id=>{return id>(this.lastNotificationId-100)});this.shownPopupIds=new Set(cleanedIds);this.saveShownPopups()}}catch(err){console.warn('Error loading shown popups:',err);this.shownPopupIds=new Set()}}saveShownPopups(){try{const ids=Array.from(this.shownPopupIds);localStorage.setItem('optima_shown_popup_ids',JSON.stringify(ids))}catch(err){console.warn('Error saving shown popups:',err)}}init(){this.badge=document.getElementById('notificationBadge');this.dropdownMenu=document.getElementById('notificationDropdownMenu');this.initSound();this.updateCount();setTimeout(()=>{this.pollForNotifications()},1000);this.startPolling();const notificationDropdown=document.querySelector('[data-bs-toggle="dropdown"]');if(notificationDropdown){notificationDropdown.addEventListener('click',()=>{setTimeout(()=>{this.updateCount();this.fetchRecent()},100)})}}initSound(){const savedPref=localStorage.getItem('optima_notification_sound');if(savedPref !==null){this.enableSound=savedPref==='true'}}playSound(notification){if(!this.enableSound)return;try{if(window.NotificationSound){if(notification.type==='critical'||notification.priority>=5){window.NotificationSound.playCriticalAlert()}else if(notification.type==='success'){window.NotificationSound.playSuccessSound()}else{window.NotificationSound.playNotificationBeep()}}}catch(err){console.warn('Error playing sound:',err)}}toggleSound(){this.enableSound=!this.enableSound;localStorage.setItem('optima_notification_sound',this.enableSound);const status=this.enableSound ? 'enabled':'disabled';this.showSimpleToast(`Notification sound ${status}`,'info')}async processNotificationQueue(){if(this.isShowingNotification||this.notificationQueue.length===0){return}const notification=this.notificationQueue.shift();this.isShowingNotification=true;this.shownPopupIds.add(notification.id);this.saveShownPopups();console.log(`📢 Showing popup for notification ID:${notification.id}`);this.playSound(notification);await this.showNotificationPopup(notification);this.updateCount();this.animateBellIcon();this.isShowingNotification=false;if(this.notificationQueue.length>0){setTimeout(()=>{this.processNotificationQueue()},500)}}animateBellIcon(){const bellIcon=document.querySelector('.nav-link i.fa-bell');const badge=this.badge;if(bellIcon){bellIcon.classList.add('notification-bell-ring');setTimeout(()=>{bellIcon.classList.remove('notification-bell-ring')},500)}if(badge){badge.classList.add('notification-badge-pulse');setTimeout(()=>{badge.classList.remove('notification-badge-pulse')},1800)}}showNotificationPopup(notification){return new Promise((resolve)=>{let icon='info';let iconColor='#3b82f6';switch(notification.type){case 'success':icon='success';iconColor='#10b981';break;case 'warning':icon='warning';iconColor='#f59e0b';break;case 'error':case 'critical':icon='error';iconColor='#ef4444';break;default:icon='info';iconColor='#3b82f6'}const toast=Swal.mixin({toast:true,position:'top-end',showConfirmButton:false,timer:5000,timerProgressBar:true,didOpen:(toast)=>{toast.addEventListener('mouseenter',Swal.stopTimer);toast.addEventListener('mouseleave',Swal.resumeTimer);if(notification.url){toast.style.cursor='pointer';toast.addEventListener('click',()=>{window.location.href=notification.url})}},willClose:()=>{resolve()}});const titleText=(notification.title||'Notification').replace(/<[^>]*>/g,'').replace(/\s+/g,' ').trim();const messageText=(notification.message||'').replace(/<[^>]*>/g,'').replace(/\s+/g,' ').trim();toast.fire({icon:icon,iconColor:iconColor,title:titleText,text:messageText,showClass:{popup:'animate__animated animate__fadeInRight animate__faster'},hideClass:{popup:'animate__animated animate__fadeOutRight animate__faster'},customClass:{popup:'notification-toast-simple',title:'notification-toast-title',htmlContainer:'notification-toast-message'}}).then(()=>{resolve()})})}startPolling(){if(this.isPolling)return;this.isPolling=true;console.log('🔄 Starting notification polling...');this.pollingTimer=setInterval(()=>{this.pollForNotifications()},this.pollingInterval)}stopPolling(){if(this.pollingTimer){clearInterval(this.pollingTimer);this.pollingTimer=null}this.isPolling=false;console.log('⏹️ Stopped notification polling')}triggerImmediateCheck(){console.log('🚀 Triggering immediate notification check...');this.pollForNotifications()}async pollForNotifications(){try{const response=await fetch(`${this.baseUrl}/notifications/poll?lastId=${this.lastNotificationId}`,{headers:{'X-Requested-With':'XMLHttpRequest'}});if(!response.ok){console.warn('⚠️ Polling failed:',response.status);return}const data=await response.json();if(data.success&&data.notifications){if(data.lastId>this.lastNotificationId){this.lastNotificationId=data.lastId}if(data.notifications.length>0){console.log(`🔔 Received ${data.notifications.length}new notifications`);const newNotifications=data.notifications.filter(n=>{return !this.shownPopupIds.has(n.id)});console.log(`📢 ${newNotifications.length}notifications ready for popup(${data.notifications.length-newNotifications.length}already shown)`);newNotifications.forEach(notification=>{this.notificationQueue.push(notification)});this.processNotificationQueue();if(this.dropdownMenu&&this.dropdownMenu.classList.contains('show')){this.fetchRecent()}}}}catch(error){console.warn('⚠️ Polling error:',error.message)}}async updateCount(){try{const response=await fetch(`${this.baseUrl}/notifications/count`,{headers:{'X-Requested-With':'XMLHttpRequest'}});if(!response.ok){console.warn('⚠️ Count update failed:',response.status);return}const data=await response.json();const count=data.count||0;if(this.badge){this.badge.textContent=count;this.badge.style.display=count>0 ? 'inline-block':'none'}const sidebarBadge=document.getElementById('sidebarNotificationCount');if(sidebarBadge){sidebarBadge.textContent=count;sidebarBadge.style.display=count>0 ? 'inline':'none'}}catch(error){console.warn('⚠️ Count update error:',error.message)}}async fetchRecent(){try{const response=await fetch(`${this.baseUrl}/notifications/get?limit=5`,{headers:{'X-Requested-With':'XMLHttpRequest'}});if(!response.ok){console.warn('⚠️ Fetch recent failed:',response.status);return}const data=await response.json();if(data.success&&data.notifications){this.updateDropdownContent(data.notifications)}}catch(error){console.warn('⚠️ Fetch recent error:',error.message)}}updateDropdownContent(notifications){if(!this.dropdownMenu)return;const existingItems=this.dropdownMenu.querySelectorAll('.notification-item');existingItems.forEach(item=>item.remove());let html='';if(notifications.length===0){html=`<li class="notification-item"><div class="text-center py-3"><i class="fas fa-bell-slash text-muted" style="font-size:2rem;"></i><p class="text-muted mb-0 small mt-2">Tidak ada notifikasi</p></div></li>`}else{notifications.forEach(notification=>{const isRead=notification.is_read=='1';const readClass=isRead ? '':'unread';const unreadDot=isRead ? '':'<span class="position-absolute top-0 start-100 translate-middle p-1 bg-danger border border-light rounded-circle" style="font-size:0.5rem;"></span>';html+=`<li class="notification-item ${readClass}" data-id="${notification.id}" data-read="${notification.is_read}"><a class="dropdown-item" href="${this.getNotificationUrl(notification)}" onclick="markAsRead(${notification.id})"><div class="d-flex align-items-start position-relative"><i class="fas fa-${this.getNotificationIcon(notification.type)}text-${this.getNotificationColor(notification.type)}me-2 mt-1"></i><div class="flex-grow-1"><div class="fw-bold small">${notification.title}</div><div class="text-muted small">${notification.message}</div><div class="text-muted" style="font-size:0.7rem;">${this.formatDate(notification.created_at)}</div></div>${unreadDot}</div></a></li>`})}const divider=this.dropdownMenu.querySelector('.dropdown-divider');if(divider){divider.insertAdjacentHTML('beforebegin',html)}}getNotificationUrl(notification){if(notification.related_id&&notification.related_id>0){if(notification.related_module==='spk'){return `${this.baseUrl}/marketing/spk/detail/${notification.related_id}`}else if(notification.related_module==='work_order'){return `${this.baseUrl}/service/work-orders/detail/${notification.related_id}`}else if(notification.related_module==='purchase_order'){return `${this.baseUrl}/purchasing/po/detail/${notification.related_id}`}}return notification.url||`${this.baseUrl}/notifications`}getNotificationIcon(type){const icons={'info':'info-circle','success':'check-circle','warning':'exclamation-triangle','error':'times-circle','critical':'exclamation-circle'};return icons[type]||'bell'}getNotificationColor(type){const colors={'info':'primary','success':'success','warning':'warning','error':'danger','critical':'danger'};return colors[type]||'primary'}formatDate(dateString){const date=new Date(dateString);const now=new Date();const diff=now-date;if(diff<60000)return 'Baru saja';if(diff<3600000)return `${Math.floor(diff/60000)}menit lalu`;if(diff<86400000)return `${Math.floor(diff/3600000)}jam lalu`;if(diff<604800000)return `${Math.floor(diff/86400000)}hari lalu`;return date.toLocaleDateString('id-ID')}showToast(notification){if(typeof Swal !=='undefined'){Swal.fire({title:notification.title||'Notifikasi',text:notification.message||'',icon:this.getIconType(notification.type),toast:true,position:'top-end',showConfirmButton:false,timer:5000,timerProgressBar:true})}else{if(Notification.permission==='granted'){new Notification(notification.title||'Notifikasi',{body:notification.message||'',icon:'/optima/public/assets/img/logo.png'})}}}showSimpleToast(message,type='info'){if(typeof Swal !=='undefined'){Swal.fire({text:message,icon:type,toast:true,position:'top-end',showConfirmButton:false,timer:3000,timerProgressBar:true})}}getIconType(type){const iconMap={'success':'success','warning':'warning','error':'error','info':'info'};return iconMap[type]||'info'}markAsRead(notificationId){fetch(`${this.baseUrl}/notifications/mark-as-read/${notificationId}`,{method:'POST',headers:{'Content-Type':'application/json','X-Requested-With':'XMLHttpRequest'}}).then(response=>{if(response.ok){const notificationItem=document.querySelector(`[data-id="${notificationId}"]`);if(notificationItem){notificationItem.classList.remove('unread');notificationItem.setAttribute('data-read','1');const unreadDot=notificationItem.querySelector('.position-absolute');if(unreadDot){unreadDot.remove()}}this.updateCount()}}).catch(error=>{console.error('Error marking notification as read:',error)})}markAllAsRead(){fetch(`${this.baseUrl}/notifications/mark-all-as-read`,{method:'POST',headers:{'Content-Type':'application/json','X-Requested-With':'XMLHttpRequest'}}).then(response=>{if(response.ok){const notificationItems=document.querySelectorAll('.notification-item');notificationItems.forEach(item=>{item.classList.remove('unread');item.setAttribute('data-read','1');const unreadDot=item.querySelector('.position-absolute');if(unreadDot){unreadDot.remove()}});this.updateCount();console.log('✅ All notifications marked as read')}}).catch(error=>{console.error('Error marking all notifications as read:',error)})}destroy(){this.stopPolling();console.log('🗑️ Notification client destroyed')}}document.addEventListener('DOMContentLoaded',function(){window.optimaNotification=new OptimaNotificationLightweight();console.log('🔍 Notification client initialized:',window.optimaNotification);console.log('🔍 markAsRead method exists:',typeof window.optimaNotification.markAsRead);console.log('🔍 markAllAsRead method exists:',typeof window.optimaNotification.markAllAsRead);window.updateNotificationCount=function(){if(window.optimaNotification){window.optimaNotification.updateCount()}};window.fetchRecentNotifications=function(){if(window.optimaNotification){window.optimaNotification.fetchRecent()}};window.markAsRead=function(notificationId){if(window.optimaNotification){window.optimaNotification.markAsRead(notificationId)}};window.markAllAsRead=function(){console.log('🔍 Global markAllAsRead called');console.log('🔍 optimaNotification exists:',!!window.optimaNotification);console.log('🔍 markAllAsRead method exists:',typeof window.optimaNotification?.markAllAsRead);if(window.optimaNotification&&typeof window.optimaNotification.markAllAsRead==='function'){window.optimaNotification.markAllAsRead()}else{console.error('❌ optimaNotification.markAllAsRead is not a function')}}});window.addEventListener('beforeunload',function(){if(window.optimaNotification){window.optimaNotification.destroy()}});window.checkNotificationsNow=function(){if(window.optimaNotification&&typeof window.optimaNotification.triggerImmediateCheck==='function'){window.optimaNotification.triggerImmediateCheck()}else{console.warn('Notification client not ready yet')}};